import { describe, it, expect } from 'vitest';
import {
  validateOrderItems,
  isValidStatusTransition,
  validateStatusTransition,
} from '../../src/validators/order.validator.js';
import type { OrderItem, OrderStatus } from '../../src/models/order.js';

describe('Order Validators', () => {
  describe('validateOrderItems', () => {
    it('should pass when items are present', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
      ];
      expect(() => validateOrderItems(items)).not.toThrow();
    });

    it('should throw when items array is empty', () => {
      expect(() => validateOrderItems([])).toThrow(
        'Order must have at least one item',
      );
    });

    it('should pass with multiple items', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        { productId: 'p2', name: 'Gadget', quantity: 3, unitPrice: 25 },
      ];
      expect(() => validateOrderItems(items)).not.toThrow();
    });
  });

  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'cancelled'];
      for (const s of statuses) {
        expect(isValidStatusTransition('delivered', s)).toBe(false);
      }
    });

    it('should reject cancelled -> any', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered'];
      for (const s of statuses) {
        expect(isValidStatusTransition('cancelled', s)).toBe(false);
      }
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import { detectUserChanges } from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

describe('User Validators', () => {
  const baseUser: User = {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date('2024-01-01'),
    updatedAt: new Date('2024-01-01'),
  };

  describe('detectUserChanges', () => {
    it('should detect name change', () => {
      const changes = detectUserChanges(baseUser, { name: 'Bob' });
      expect(changes).toEqual(['name']);
    });

    it('should detect email change', () => {
      const changes = detectUserChanges(baseUser, { email: 'bob@example.com' });
      expect(changes).toEqual(['email']);
    });

    it('should detect role change', () => {
      const changes = detectUserChanges(baseUser, { role: 'admin' });
      expect(changes).toEqual(['role']);
    });

    it('should detect multiple changes', () => {
      const changes = detectUserChanges(baseUser, {
        name: 'Bob',
        email: 'bob@example.com',
        role: 'admin',
      });
      expect(changes).toEqual(['name', 'email', 'role']);
    });

    it('should return empty array when nothing changed', () => {
      const changes = detectUserChanges(baseUser, {
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });
      expect(changes).toEqual([]);
    });

    it('should return empty array for empty input', () => {
      const changes = detectUserChanges(baseUser, {});
      expect(changes).toEqual([]);
    });

    it('should ignore undefined fields', () => {
      const changes = detectUserChanges(baseUser, {
        name: undefined,
        email: 'new@example.com',
      });
      expect(changes).toEqual(['email']);
    });
  });
});

